# setup_usuarios.ps1 - Sistema de usuarios con roles por area
Write-Host "Instalando sistema de usuarios..." -ForegroundColor Cyan

$dir = Split-Path "src\store\erp.auth.store.ts" -Parent
if ($dir) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\store\erp.auth.store.ts", $text, [System.Text.Encoding]::UTF8)
Write-Host "  OK: src/store/erp.auth.store.ts" -ForegroundColor Yellow

